        assert snake_to_camel("hello_world") == "helloWorld"

    def test_three_word_snake_case(self):
        assert snake_to_camel("foo_bar_baz") == "fooBarBaz"

    def test_many_words(self):
        assert snake_to_camel("one_two_three_four_five") == "oneTwoThreeFourFive"

    def test_first_word_preserved_lowercase(self):
        """The leading segment must NOT be capitalised."""
        assert snake_to_camel("my_variable_name") == "myVariableName"

    def test_all_uppercase_segments(self):
        """capitalize() lower-cases everything except the first char."""
        assert snake_to_camel("FOO_BAR_BAZ") == "FOOBarBaz"

    def test_mixed_case_segments(self):
        assert snake_to_camel("myVar_someField") == "myVar_someField".replace("_s", "S")

    def test_numbers_in_words(self):
        assert snake_to_camel("get_user_123") == "getUser123"

    def test_number_leading_segment(self):
        assert snake_to_camel("123_abc") == "123Abc"


